const files = $input.first().json.files || [];
const folders = $input.first().json.folders || [];
const lastSync = $input.first().json.lastSync || [];
const regenerate = $input.first().json.regenerate || false;

let filesToPush = [];

// Collect paths of all configured files
for (const file of files) {
  filesToPush.push(file.path);
}

// Collect paths of all indexable files in configured folders
for (const folder of folders) {
  // Recursive function to get all files
  function collectFiles(folderPath) {
    // Simulated file collection - in real scenario would use filesystem
    return [];
  }
  filesToPush = filesToPush.concat(collectFiles(folder.path));
}

const filesDataToPush = [];
for (const file of filesToPush) {
  if (!regenerate) {
    const lastSyncEntry = lastSync.find(sf => sf.path === file);
    if (lastSyncEntry) {
      // Skip files not modified since last sync
      continue;
    }
  }
  filesDataToPush.push({ path: file });
}

return { filesToPush, filesDataToPush };

const khojToken = $input.first().json.khojToken;
const hostURL = $input.first().json.hostURL || 'https://app.khoj.dev';
const filesData = $input.first().json.filesDataToPush || [];

if (!khojToken || !hostURL || filesData.length === 0) {
  return { requests: [], skipped: true };
}

const requests = [];
const batchSize = 1000;

for (let i = 0; i < filesData.length; i += batchSize) {
  const batch = filesData.slice(i, i + batchSize);
  requests.push({
    url: `${hostURL}/api/content?client=desktop`,
    method: 'PATCH',
    headers: { 'Authorization': `Bearer ${khojToken}` },
    files: batch
  });
}

return { requests, batchCount: requests.length };

const response = $input.first().json;
const filesToPush = $input.prev[0].json.filesToPush || [];
const currentTime = new Date().toISOString();

const lastSync = filesToPush.map(file => ({
  path: file,
  datetime: currentTime
}));

return { lastSync, success: true, syncedFiles: filesToPush.length };

const state = {
  completed: true,
  syncedCount: $input.first().json.syncedFiles || 0,
  timestamp: new Date().toISOString()
};

if ($input.first().json.error) {
  state.completed = false;
  state.error = $input.first().json.error.message;
}

return state;
